msgContent:
{
  "content": "#### <font color=\"#ff0000\">生产环境服务器告警</font>\n\n**服务名称**: {$serviceName}\n**主机IP**: {$hostIp}\n**告警级别**: {$alertLevel}\n**当前状态**: {$status}\n\n**异常信息**:\n```json\n{$errorMessage}\n```\n\n请立即前往监控平台排查: {$monitorLink}",
  "content_params_schema": [
    {
      "key": "serviceName",
      "description": "故障服务名称",
      "type": "string",
      "required": true,
      "defaultValue": "Unknown Service"
    },
    {
      "key": "hostIp",
      "description": "故障主机IP",
      "type": "string",
      "required": true,
      "defaultValue": "0.0.0.0"
    },
    {
      "key": "alertLevel",
      "description": "告警级别",
      "type": "string",
      "required": true,
      "defaultValue": "CRITICAL"
    },
    {
      "key": "status",
      "description": "当前状态",
      "type": "string",
      "required": true,
      "defaultValue": "DOWN"
    },
    {
      "key": "errorMessage",
      "description": "异常堆栈或错误信息",
      "type": "string",
      "required": true,
      "defaultValue": "Connection timed out"
    },
    {
      "key": "monitorLink",
      "description": "监控详情页链接",
      "type": "string",
      "required": false,
      "defaultValue": ""
    }
  ],
  "extra_params_schema": [
    {
      "key": "sendType",
      "description": "钉钉机器人发送类型",
      "type": "string",
      "required": true,
      "defaultValue": "markdown"
    },
    {
      "key": "title",
      "description": "钉钉 markdown 标题",
      "type": "string",
      "required": true,
      "defaultValue": "生产环境服务器告警"
    }
  ]
}
